package com.khanh.fooddelivery.restaurant_service.entity;
import com.khanh.fooddelivery.restaurant_service.common.entity.BaseAuditEntity; import com.khanh.fooddelivery.restaurant_service.enums.*; import jakarta.persistence.*; import lombok.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="restaurant_members") @Getter @Setter @NoArgsConstructor
public class RestaurantMember extends BaseAuditEntity {@Id private UUID id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="restaurant_id") private Restaurant restaurant; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="branch_id") private RestaurantBranch branch; @Column(nullable=false) private UUID userId; @Enumerated(EnumType.STRING) @Column(nullable=false) private RestaurantMemberRole role; @Enumerated(EnumType.STRING) @Column(nullable=false) private RestaurantMemberStatus status; private UUID invitedByUserId; private Instant joinedAt; @Version private long version; @PrePersist void id(){if(id==null)id=UUID.randomUUID();}}
